"use client";

import { useEffect, useMemo, useState } from "react";
import { Link, useNavigate, useParams } from "react-router-dom";
import type { ToolboxPlugin } from "../plugin-types";

type ImportedRepo = {
  id: string;
  slug: string;
  label: string;
  repoUrl: string;
  owner: string;
  repo: string;
  createdAt: number;
};

type ParsedRepo = {
  owner: string;
  repo: string;
  normalizedUrl: string;
};

const STORAGE_KEY = "toolbox-imported-repos";

function loadImportedRepos(): ImportedRepo[] {
  if (typeof window === "undefined") {
    return [];
  }

  try {
    const raw = window.localStorage.getItem(STORAGE_KEY);
    if (!raw) {
      return [];
    }

    const parsed = JSON.parse(raw) as ImportedRepo[];
    return Array.isArray(parsed) ? parsed : [];
  } catch {
    return [];
  }
}

function saveImportedRepos(items: ImportedRepo[]): void {
  if (typeof window === "undefined") {
    return;
  }

  window.localStorage.setItem(STORAGE_KEY, JSON.stringify(items));
}

function slugify(value: string): string {
  return value
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/(^-|-$)/g, "");
}

function parseGitHubRepoUrl(input: string): ParsedRepo | null {
  const value = input.trim();
  if (!value) {
    return null;
  }

  let url: URL;
  try {
    url = new URL(value);
  } catch {
    return null;
  }

  if (url.hostname !== "github.com") {
    return null;
  }

  const parts = url.pathname.split("/").filter(Boolean);
  if (parts.length < 2) {
    return null;
  }

  const owner = parts[0];
  const repo = parts[1].replace(/\.git$/i, "");

  if (!owner || !repo) {
    return null;
  }

  return {
    owner,
    repo,
    normalizedUrl: `https://github.com/${owner}/${repo}`,
  };
}

async function fetchReadme(owner: string, repo: string): Promise<string | null> {
  const candidates = [
    `https://raw.githubusercontent.com/${owner}/${repo}/main/README.md`,
    `https://raw.githubusercontent.com/${owner}/${repo}/master/README.md`,
  ];

  for (const url of candidates) {
    try {
      const response = await fetch(url);
      if (!response.ok) {
        continue;
      }

      return await response.text();
    } catch {
      // Try next candidate.
    }
  }

  return null;
}

function RepoImportWizardPage() {
  const navigate = useNavigate();
  const params = useParams();

  const [items, setItems] = useState<ImportedRepo[]>([]);
  const [repoUrl, setRepoUrl] = useState("");
  const [customLabel, setCustomLabel] = useState("");
  const [formError, setFormError] = useState<string | null>(null);
  const [status, setStatus] = useState<string | null>(null);
  const [readme, setReadme] = useState<string>("");
  const [readmeLoading, setReadmeLoading] = useState(false);

  const currentSlug = params["*"] ?? "";

  useEffect(() => {
    const nextItems = loadImportedRepos();
    setItems(nextItems);
  }, []);

  const currentItem = useMemo(() => {
    if (!currentSlug) {
      return null;
    }

    return items.find((item) => item.slug === currentSlug) ?? null;
  }, [currentSlug, items]);

  useEffect(() => {
    setReadme("");
  }, [currentSlug]);

  const handleImport = () => {
    setFormError(null);
    setStatus(null);

    const parsed = parseGitHubRepoUrl(repoUrl);
    if (!parsed) {
      setFormError("Please paste a valid GitHub repository URL.");
      return;
    }

    const baseLabel = customLabel.trim() || parsed.repo;
    const baseSlug = slugify(baseLabel) || slugify(parsed.repo) || "imported-project";

    let slug = baseSlug;
    let counter = 2;
    while (items.some((item) => item.slug === slug)) {
      slug = `${baseSlug}-${counter}`;
      counter += 1;
    }

    const nextItem: ImportedRepo = {
      id: `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
      slug,
      label: baseLabel,
      repoUrl: parsed.normalizedUrl,
      owner: parsed.owner,
      repo: parsed.repo,
      createdAt: Date.now(),
    };

    const nextItems = [nextItem, ...items];
    setItems(nextItems);
    saveImportedRepos(nextItems);

    setStatus("Project imported. A new in-app page has been created.");
    setRepoUrl("");
    setCustomLabel("");
    navigate(`/imports/${nextItem.slug}`);
  };

  const handleDelete = (id: string) => {
    const nextItems = items.filter((item) => item.id !== id);
    setItems(nextItems);
    saveImportedRepos(nextItems);

    if (currentItem && currentItem.id === id) {
      navigate("/imports");
    }
  };

  const handleLoadReadme = async () => {
    if (!currentItem) {
      return;
    }

    setReadmeLoading(true);
    const content = await fetchReadme(currentItem.owner, currentItem.repo);
    setReadmeLoading(false);
    setReadme(content ?? "README.md not found on main/master branches.");
  };

  return (
    <div className="mx-auto w-full max-w-6xl space-y-5">
      <section className="glass-card rounded-3xl p-5 md:p-6">
        <p className="text-xs font-semibold tracking-wider text-slate-600">REPO IMPORT WIZARD</p>
        <h2 className="mt-2 text-2xl font-semibold text-slate-900 md:text-3xl">Paste GitHub Link, Create App Page</h2>
        <p className="mt-2 text-sm text-slate-700">
          This wizard creates an internal Toolbox page from a repository link. It does not build or execute external source code automatically.
        </p>

        <div className="mt-4 grid gap-3 md:grid-cols-[1.3fr_1fr_auto]">
          <label className="flex flex-col gap-1 text-sm font-semibold text-slate-700">
            Repository URL
            <input
              value={repoUrl}
              onChange={(event) => setRepoUrl(event.target.value)}
              placeholder="https://github.com/owner/repo"
              className="h-11 rounded-xl border-2 border-emerald-200 bg-white px-3 text-sm font-normal text-slate-800 outline-none transition focus:border-emerald-500"
            />
          </label>

          <label className="flex flex-col gap-1 text-sm font-semibold text-slate-700">
            Page Label (optional)
            <input
              value={customLabel}
              onChange={(event) => setCustomLabel(event.target.value)}
              placeholder="My Imported Project"
              className="h-11 rounded-xl border-2 border-emerald-200 bg-white px-3 text-sm font-normal text-slate-800 outline-none transition focus:border-emerald-500"
            />
          </label>

          <div className="flex items-end">
            <button
              type="button"
              onClick={handleImport}
              className="h-11 rounded-xl border-2 border-emerald-500 bg-emerald-600 px-4 text-sm font-semibold text-white transition hover:bg-emerald-500"
            >
              Import
            </button>
          </div>
        </div>

        {formError && <p className="mt-2 text-sm font-semibold text-rose-700">{formError}</p>}
        {status && (
          <p className="mt-2 text-sm font-semibold text-emerald-700" role="status" aria-live="polite">
            {status}
          </p>
        )}
      </section>

      <section className="grid gap-4 lg:grid-cols-[0.95fr_1.05fr]">
        <div className="glass-card rounded-2xl p-4 md:p-5">
          <h3 className="text-lg font-semibold text-slate-900">Imported Projects</h3>
          {items.length === 0 ? (
            <p className="mt-3 text-sm text-slate-700">No imported projects yet. Paste a GitHub link above to begin.</p>
          ) : (
            <ul className="mt-3 space-y-2">
              {items.map((item) => (
                <li key={item.id} className="rounded-xl border border-emerald-100 bg-white/80 p-3">
                  <div className="flex items-start justify-between gap-2">
                    <div>
                      <Link to={`/imports/${item.slug}`} className="text-sm font-semibold text-emerald-700 hover:text-emerald-600">
                        {item.label}
                      </Link>
                      <p className="mt-1 text-xs text-slate-600">{item.owner}/{item.repo}</p>
                    </div>
                    <button
                      type="button"
                      onClick={() => handleDelete(item.id)}
                      className="rounded-lg border border-rose-200 bg-white px-2 py-1 text-xs font-semibold text-rose-700 hover:bg-rose-50"
                    >
                      Remove
                    </button>
                  </div>
                </li>
              ))}
            </ul>
          )}
        </div>

        <div className="glass-card rounded-2xl p-4 md:p-5">
          {!currentItem ? (
            <div>
              <h3 className="text-lg font-semibold text-slate-900">Project Preview</h3>
              <p className="mt-2 text-sm text-slate-700">Select a project from the list to open its dedicated Toolbox page.</p>
            </div>
          ) : (
            <div>
              <h3 className="text-lg font-semibold text-slate-900">{currentItem.label}</h3>
              <p className="mt-1 text-sm text-slate-700">{currentItem.owner}/{currentItem.repo}</p>

              <div className="mt-3 flex flex-wrap gap-2">
                <a
                  href={currentItem.repoUrl}
                  target="_blank"
                  rel="noreferrer"
                  className="rounded-lg border-2 border-emerald-200 bg-white px-3 py-2 text-xs font-semibold text-emerald-700 hover:bg-emerald-50"
                >
                  Open Repository
                </a>
                <a
                  href={`https://${currentItem.owner}.github.io/${currentItem.repo}/`}
                  target="_blank"
                  rel="noreferrer"
                  className="rounded-lg border-2 border-slate-200 bg-white px-3 py-2 text-xs font-semibold text-slate-700 hover:bg-slate-50"
                >
                  Try Live Page
                </a>
                <button
                  type="button"
                  onClick={handleLoadReadme}
                  className="rounded-lg border-2 border-emerald-500 bg-emerald-600 px-3 py-2 text-xs font-semibold text-white hover:bg-emerald-500"
                  disabled={readmeLoading}
                >
                  {readmeLoading ? "Loading README..." : "Load README"}
                </button>
              </div>

              {readme && (
                <pre className="mt-3 max-h-80 overflow-auto rounded-xl border border-emerald-100 bg-slate-950 p-3 text-xs leading-6 text-emerald-100">
                  {readme}
                </pre>
              )}
            </div>
          )}
        </div>
      </section>
    </div>
  );
}

const repoImporterPlugin: ToolboxPlugin = {
  id: "repo-import-wizard",
  name: "Repo Import Wizard",
  version: "0.1.0",
  routes: [
    {
      path: "/imports/*",
      element: <RepoImportWizardPage />,
    },
  ],
  menu: [
    {
      label: "Repo Wizard",
      to: "/imports",
      icon: "RG",
    },
  ],
};

export default repoImporterPlugin;
